// 1. 抓取剛剛建好的「主訂單 ID」
const recordId = $input.first().json.id;

// 2. 獲取打包好的子項目清單
const subItems = $('Calculate Profit & Pack Items').first().json.Sub_Items || [];

// 3. 轉換為 n8n 資料格式
// Product_ID 為空時跳過 - 因為 null 會在 Airtable 報錯 [null]，
// linked record 不接受 null ID，此處 Create Sub Items 報錯會卡住 Telegram 戰報
return subItems
  .filter(item => item.Order_Item_Key)
  .map(item => {
    const row = {
      Quantity: item.Quantity,
      Notes: item.Notes,
      Main_Order_ID: recordId,
      Order_Item_Key: item.Order_Item_Key
    };
    if (item.Product_Record_ID) row.Product_ID = item.Product_Record_ID;
    return { json: row };
  });

// API V40.6 ??:???? SKU (Supabase-Ready ?)
// ????:?? batchFormula ??? Airtable ????
// ??:sku_list ????? Supabase RPC ????
const items = $input.all();

if (!Array.isArray(items) || items.length === 0) {
    return { json: { batchFormula: "RECORD_ID()='INVALID'", sku_list: [], hasItems: false } };
}

const skus = [...new Set(items.map(i => i.json.Search_SKU).filter(s => s && s !== "???"))];

if (skus.length === 0) {
    return { json: { batchFormula: "RECORD_ID()='INVALID'", sku_list: [], hasItems: false } };
}

const formulaParts = skus.map(s => `{Product_Name} = '${s}'`);
const finalFormula = skus.length > 1 ? `OR(${formulaParts.join(',')})` : formulaParts[0];

// sku_list: Supabase get_base_cost_by_skus RPC ????
// Phase 2 ???,n8n HTTP Request ?????????
return { json: { batchFormula: finalFormula, sku_list: skus, hasItems: true } };

// API V40.6 Supabase-First: reads costs from Supabase (via Smart Cache Strategist)
// Fallback: Airtable node output (if Smart Cache Strategist couldn't reach Supabase)
const originalItemsNode = $("Parse Items & Generate SKU");
const originalItems = originalItemsNode ? originalItemsNode.all() : [];

// Check if Smart Cache Strategist already fetched costs from Supabase
const cacheData = $("Smart Cache Strategist").first().json;

let costMap = {};

if (cacheData.supabaseFetched && cacheData.supabaseCosts) {
  // Supabase path: cost data pre-fetched, keyed by Product_Name
  costMap = cacheData.supabaseCosts;
} else {
  // Airtable fallback: read from Fetch Exact Base Cost node output
  const costNode = $("Fetch Exact Base Cost");
  const costResults = costNode ? costNode.all() : [];
  costResults.forEach(r => {
    if (r.json && r.json.id) {
      costMap[r.json.Product_Name] = {
        id: r.json.id,
        Product_Name: r.json.Product_Name,
        Total_Base_Cost: Number(r.json.Total_Base_Cost) || 0
      };
    }
  });
}

return originalItems.map(item => {
  const sku = item.json.Search_SKU;
  // Section 14.5 ????:????????? 0(?? V40.9 ?????)
  const costData = costMap[sku] || { id: null, Product_Name: sku, Total_Base_Cost: 0 };
  return { json: { ...item.json, ...costData } };
});

// === Freehandsss V47.5 (??????: item ?? + order ?? + n8n_cost_adjustments) ===
// ??:N8n_Cost_Adjustments = NUMERIC ????,N8n_Adjustment_Notes = JSONB ????
// ??:.fhs/ai/FHS_Finance_Bible.md �3-4, Product Bible V3.7 �2.5

const parseNode = $('Parse Items & Generate SKU');
const parseNodeItems = parseNode ? parseNode.all() : [];

if (parseNodeItems.length === 0) {
    return [{ json: { Total_Revenue: 0, Total_Cost: 0, Final_Profit: 0, Sub_Items: [],
        Cost_Lookup_Warning: "", Has_Cost_Error: false,
        Handmodel_Cost_Total: 0, Keychain_Cost_Total: 0, Necklace_Cost_Total: 0,
        N8n_Cost_Adjustments: 0, N8n_Adjustment_Notes: [] } }];
}

const firstNodeData = parseNodeItems[0].json || {};
const totalRevenue = Number(firstNodeData.Total_Revenue) || 0;
const rawFormState = firstNodeData.Raw_Form_State || "";

let deposit = 0, balance = 0, additionalFee = 0;
try {
    const triggerNode = $('Receive Dashboard Order');
    const triggerBody = (triggerNode && triggerNode.first()) ? (triggerNode.first().json.body || triggerNode.first().json) : {};
    deposit = Number(triggerBody.Deposit) || 0;
    balance = Number(triggerBody.Balance) || 0;
    additionalFee = Number(triggerBody.Additional_Fee) || 0;
} catch (error) {}

// SKU ? item_category ??(Finance Bible �3)
function getItemCategory(sku) {
    if (sku.includes('??') || sku.includes('???')) return '????';
    if (sku.includes('???')) return '?????';
    if (sku.includes('??')) return '??';
    return '??';
}

let totalBaseCost = 0;
let handmodelCostTotal = 0;
let keychainCostTotal = 0;
let necklaceCostTotal = 0;
let packedItems = [];
let keychainItemCount = 0;
const zeroCostItems = [];

const items = $input.all();
for (let i = 0; i < parseNodeItems.length; i++) {
    let originalItemData = parseNodeItems[i].json || {};
    let itemData = (items[i] && items[i].json) ? items[i].json : originalItemData;

    let itemCost = Number(itemData.Total_Base_Cost) || 0;
    totalBaseCost += itemCost;

    const sku = originalItemData.Search_SKU || itemData.Search_SKU || "";
    if (sku.includes("???")) keychainItemCount++;

    if (itemCost === 0 && sku && sku !== "???" && sku.trim() !== "") {
        zeroCostItems.push(sku);
    }

    const itemCategory = getItemCategory(sku);
    const itemHandmodelCost = itemCategory === '????'  ? itemCost : 0;
    const itemKeychainCost  = itemCategory === '?????' ? itemCost : 0;
    const itemNecklaceCost  = itemCategory === '??'      ? itemCost : 0;

    handmodelCostTotal += itemHandmodelCost;
    keychainCostTotal  += itemKeychainCost;
    necklaceCostTotal  += itemNecklaceCost;

    packedItems.push({
        Product_Record_ID: itemData.id || null,
        Product_Name:      itemData.Product_Name || originalItemData.Search_SKU || "Unknown SKU",
        Total_Base_Cost:   itemCost,
        Quantity:          Number(originalItemData.Original_Qty) || 1,
        Notes:             originalItemData.Item_Notes || "",
        Order_Item_Key:    originalItemData.Order_Item_Key || "",
        Item_Category:     itemCategory,
        Handmodel_Cost:    itemHandmodelCost,
        Keychain_Cost:     itemKeychainCost,
        Necklace_Cost:     itemNecklaceCost
    });
}

// ????????????(V3.7 �2.5)
const keychainShippingDeduction = keychainItemCount > 1 ? (keychainItemCount - 1) * 20 : 0;
totalBaseCost     -= keychainShippingDeduction;
keychainCostTotal -= keychainShippingDeduction;

// N8n_Cost_Adjustments = NUMERIC ????(??)
// N8n_Adjustment_Notes = JSONB ????(?????,?????)
const n8nAdjustmentNotes = [];
if (keychainShippingDeduction > 0) {
    n8nAdjustmentNotes.push({
        type:                "keychain_shipping_deduction",
        amount:              -keychainShippingDeduction,
        desc:                `${keychainItemCount} ????????,?? ${keychainItemCount - 1} ?????(?? $20)`,
        basis:               "Product Bible V3.7 �2.5",
        keychain_item_count: keychainItemCount
    });
}
const n8nCostAdjustments = n8nAdjustmentNotes.reduce((sum, item) => sum + (item.amount || 0), 0);

const finalProfit = totalRevenue - totalBaseCost;

const hasCostError = zeroCostItems.length > 0;
const costLookupWarning = hasCostError
    ? `?? SKU ??????,Total_Cost ????!\n?????? = $0:\n${zeroCostItems.map(s => `. ${s}`).join('\n')}`
    : "";

return [{
    json: {
        ...firstNodeData,
        Total_Revenue:        totalRevenue,
        Total_Cost:           totalBaseCost,
        Final_Profit:         finalProfit,
        Deposit:              deposit,
        Balance:              balance,
        Additional_Fee:       additionalFee,
        Raw_Form_State:       rawFormState,
        Sub_Items:            packedItems,
        Cost_Lookup_Warning:  costLookupWarning,
        Has_Cost_Error:       hasCostError,
        Handmodel_Cost_Total: handmodelCostTotal,
        Keychain_Cost_Total:  keychainCostTotal,
        Necklace_Cost_Total:  necklaceCostTotal,
        N8n_Cost_Adjustments: n8nCostAdjustments,
        N8n_Adjustment_Notes: n8nAdjustmentNotes
    }
}];

// === V45.7.4 Parse Items & Generate SKU (SKU Normalization Layer) ===
const body = $("Receive Dashboard Order").first().json.body || $("Receive Dashboard Order").first().json;
const orderId = body.Order_ID || "未命名";
const customer = body.Customer_Name || "未命名";
const appDate = body.Appointment_Date || null;
const confirmDate = body.Order_Confirm_Date || null;
const revenue = (body.Deposit || 0) + (body.Balance || 0) + (body.Additional_Fee || 0);
const rawText = body.Full_Order_Text || "";
const rawState = body.Raw_Form_State || "";

let outputItems = [];

// V45.7.4: Support both Order_Items_List (Dashboard) and Items (legacy/test)
const itemsList = body.Order_Items_List || body.Items;

if (itemsList && Array.isArray(itemsList)) {
    for (const item of itemsList) {
        let sku = item.Product_Name || "";
        const qty = Number(item.Quantity) || 1;

        // === 1. 3D Display SKU Normalization (Bible V3.7 Section 4) ===
        // Handles: 木框款式/木框套裝/立體擺設(木框) → 木框套裝 (N肢)
        // Rule: 3肢 maps to 4肢 pricing per V3.7
        if (sku.includes("木框")) {
            let limb = (sku.includes("4肢") || sku.includes("3肢")) ? "(4肢)" : "(2肢)";
            sku = `木框套裝 ${limb}`;
        } else if (sku.includes("玻璃瓶")) {
            let limb = (sku.includes("4肢") || sku.includes("3肢")) ? "(4肢)" : "(2肢)";
            sku = `玻璃瓶套裝 ${limb}`;
        }

        // === 2. Keychain SKU Normalization ===
        // Dashboard sends: "嬰兒鎖匙扣 - 不銹鋼" + Mode: "(加購)"
        // Airtable expects: "嬰兒鎖匙扣 - 不銹鋼 - {qty}飾 {mode}"
        if (sku.includes("鎖匙扣") && item.Mode) {
            sku = `${sku} - ${qty}飾 ${item.Mode}`;
        }

        // === 3. Jewelry/Charm SKU Normalization ===
        // Dashboard sends: "嬰兒吊飾 - 925銀" + Mode: "(加購)"
        // Airtable expects: "嬰兒吊飾 - 925銀 - {qty}飾 {mode}"
        if (sku.includes("吊飾") && item.Mode) {
            sku = `${sku} - ${qty}飾 ${item.Mode}`;
        }

        let shipping_saved = (sku.includes("鎖匙扣") && qty > 1) ? (qty - 1) * 20 : 0;
        let necklace_saved = (sku.includes("吊飾")) ? Math.floor(qty / 2) * 220 : 0;

        outputItems.push({
            json: {
                Order_ID: orderId,
                Customer_Name: customer,
                Appointment_Date: appDate,
                Order_Confirm_Date: confirmDate,
                Total_Revenue: revenue,
                Order_Text: rawText,
                Raw_Form_State: rawState,
                Search_SKU: sku,
                Original_Qty: qty,
                Item_Notes: item.Notes || "",
                Order_Item_Key: item.Order_Item_Key || "",
                Shipping_Deduction: shipping_saved,
                Necklace_Deduction: necklace_saved
            }
        });
    }
} else {
    outputItems.push({ json: { Order_ID: orderId, Customer_Name: customer, Total_Revenue: revenue, Order_Text: rawText, Raw_Form_State: rawState, Search_SKU: "無商品", Shipping_Deduction: 0, Necklace_Deduction: 0 }});
}
return outputItems;

// Profit Auditor V45.8 - Anti-Loss Guard
// Business logic: Ling Au sets prices manually; system price is reference only.
// Audit purpose: only alert if actual collected < system cost (selling at a loss)
const body = $("Receive Dashboard Order").first().json.body || $("Receive Dashboard Order").first().json;

const deposit       = Number(body.Deposit)           || 0;
const balance       = Number(body.Balance)           || 0;
const additionalFee = Number(body.Additional_Fee)    || 0;
const actualTotal   = deposit + balance + additionalFee;
const systemCost    = Number(body.System_Total_Cost) || 0;

let auditResults = {
    auditPassed: true,
    systemCost:  systemCost,
    actualTotal: actualTotal,
    discrepancy: 0,
    reasons:     [],
    orderId:     body.Order_ID      || "Unknown",
    customer:    body.Customer_Name || "Unknown",
    role:        body.Role          || "ling"
};

// Only audit when both values are meaningful (skip if no payment entered yet)
if (actualTotal > 0 && systemCost > 0) {
    if (actualTotal < systemCost) {
        const diff = systemCost - actualTotal;
        auditResults.auditPassed = false;
        auditResults.discrepancy = diff;
        auditResults.reasons.push(`At-a-loss alert: collected $${actualTotal}, cost $${systemCost}, gap $${diff}`);
    }
}

return [{ json: auditResults }];

// V47.9 Local Cost Map — fetch() unavailable in Code nodes on this NAS
// Costs from Supabase products table (2026-05-18). Base SKU = prefix before '- N飾 (...)'
const COST_MAP = {
  // 手模擺設 — exact match
  "玻璃瓶套裝 (4肢)": 210,
  "玻璃瓶套裝 (2肢)": 210,
  "木框套裝 (4肢)":   210,
  "木框套裝 (2肢)":   210,
  // 嬰兒鎖匙扣
  "嬰兒鎖匙扣 - 不銹鋼":   185,
  "嬰兒鎖匙扣 - 鋁合金":   212,
  "嬰兒(P)鎖匙扣 - 不銹鋼": 235,
  "嬰兒(P)鎖匙扣 - 鋁合金": 262,
  // 嬰兒吊飾
  "嬰兒吊飾 - 925銀":    425,
  "嬰兒吊飾 - 925金":    481,
  "嬰兒(P)吊飾 - 925銀": 475,
  "嬰兒(P)吊飾 - 925金": 531,
  // 家庭 S 系列鎖匙扣
  "家庭(S1)鎖匙扣 - 不銹鋼": 275,
  "家庭(S1)鎖匙扣 - 鋁合金": 275,
  "家庭(S2)鎖匙扣 - 不銹鋼": 275,
  "家庭(S2)鎖匙扣 - 鋁合金": 275,
  // 家庭 P 系列鎖匙扣
  "家庭(P1)鎖匙扣 - 不銹鋼": 405,
  "家庭(P1)鎖匙扣 - 鋁合金": 405,
  "家庭(P2)鎖匙扣 - 不銹鋼": 405,
  "家庭(P2)鎖匙扣 - 鋁合金": 405,
  // 家庭吊飾
  "家庭(S1)吊飾 - 925銀": 475,
  "家庭(S1)吊飾 - 925金": 531,
  "家庭(S2)吊飾 - 925銀": 475,
  "家庭(S2)吊飾 - 925金": 531,
  "家庭(P1)吊飾 - 925銀": 605,
  "家庭(P1)吊飾 - 925金": 661,
  "家庭(P2)吊飾 - 925銀": 605,
  "家庭(P2)吊飾 - 925金": 661,
  // 成人
  "成人(P)鎖匙扣 - 不銹鋼": 405,
  "成人(P)吊飾 - 925銀":    605,
};

function lookupCost(sku) {
  if (!sku) return null;
  // 1. Exact match
  if (COST_MAP[sku] !== undefined) return COST_MAP[sku];
  // 2. Prefix match (handles variants like "嬰兒鎖匙扣 - 不銹鋼 - 5飾 (加購)")
  for (const base of Object.keys(COST_MAP)) {
    if (sku.startsWith(base)) return COST_MAP[base];
  }
  return null;
}

const batchItems = $("Batch SKU Collector").all();
const hasValidItems = batchItems.some(item => item.json.hasItems === true);
const skuList = batchItems.length > 0 ? (batchItems[0].json.sku_list || []) : [];

if (hasValidItems && skuList.length > 0) {
  const supabaseCosts = {};
  for (const sku of skuList) {
    const cost = lookupCost(sku);
    if (cost !== null) {
      supabaseCosts[sku] = { Product_Name: sku, Total_Base_Cost: cost };
    }
  }
  if (Object.keys(supabaseCosts).length > 0) {
    return batchItems.map(item => ({
      json: {
        ...item.json,
        useCache: false,
        supabaseFetched: true,
        supabaseCosts,
        batchFormula: "RECORD_ID()='SUPABASE_SKIP'"
      }
    }));
  }
}

// No costs found in local map — fall through to Airtable
if (hasValidItems) {
  await new Promise(r => setTimeout(r, 250));
}
return batchItems.map(item => ({
  json: { ...item.json, useCache: false, supabaseFetched: false }
}));

